Method.Source:
void copyHeader()
{
    FWFTextBlockInstance    sourceInstance, targetInstance;
    Common                  sourceRecord;

    if (this.tmpFrmVirtualLines.TableNum == tableNum(PurchReqLine))
    {
        sourceRecord = PurchReqTable::findPurchReqId(this.tmpFrmVirtualLines.Id);
    }

    next copyHeader();

    if (this.parmCopyHeaderTextBlock())
    {
        //delete texts from setup
        delete_from targetInstance
            where targetInstance.RefTableId == purchReqTable.TableId
               && targetInstance.RefRecId   == purchReqTable.RecId;

        while select sourceInstance
            where sourceInstance.RefTableId == sourceRecord.TableId
               && sourceInstance.RefRecId   == sourceRecord.RecId
        {
            targetInstance = sourceInstance.copyToTarget(purchReqTable, true);
        }
    }
}

protected void copyLine(TmpFrmVirtual _tmpFrmVirtualLines)
{
    FWFTextBlockInstance    sourceInstance, targetInstance;
    PurchReqLine            purchReqLine;
    Common                  sourceRecord = PurchReqLine::find(_tmpFrmVirtualLines.RecordNo);

    next copyLine(_tmpFrmVirtualLines);

    if (this.parmCopyLineTextBlock())
    {
        select firstonly purchReqLine order by RecId desc;

        //delete texts from setup
        delete_from targetInstance
            where targetInstance.RefTableId == purchReqLine.TableId
               && targetInstance.RefRecId   == purchReqLine.RecId;

        while select sourceInstance
            where sourceInstance.RefTableId == sourceRecord.TableId
               && sourceInstance.RefRecId   == sourceRecord.RecId
        {
            targetInstance = sourceInstance.copyToTarget(purchReqLine, true);
        }
    }
}
